parameters.jsCode:
// Parse job input data
const body = $input.first().json;
const jobUrl = body.job_url || '';
const jobDescription = body.job_description || body.description || '';
const company = body.company || 'Unknown Company';
const jobTitle = body.job_title || body.title || 'Software Engineer';
const location = body.location || 'Remote';
const jobRequirements = body.requirements || jobDescription;
const userSkills = body.user_skills || 'JavaScript, Python, React, Node.js, SQL, Docker, Git, REST APIs';

// SQL-safe versions (escape single quotes for SQLite)
const companySql = company.replace(/'/g, "''");
const jobTitleSql = jobTitle.replace(/'/g, "''");
const locationSql = location.replace(/'/g, "''");
const jobDescSql = jobDescription.replace(/'/g, "''").substring(0, 500);

// Shell-safe slug for git commit (alphanumeric + spaces only)
const companyShell = company.replace(/[^a-zA-Z0-9 ]/g, '').substring(0, 40);
const jobTitleShell = jobTitle.replace(/[^a-zA-Z0-9 ]/g, '').substring(0, 40);

// Create date-based folder path
const now = new Date();
const year = now.getFullYear();
const month = String(now.getMonth() + 1).padStart(2, '0');
const day = String(now.getDate()).padStart(2, '0');
const companySlug = company.replace(/[^a-zA-Z0-9]/g, '_').substring(0, 20);
const folderName = `${day}_${companySlug}`;
const vaultPath = `/home/n8n/.n8n/vault/${year}/${month}/${folderName}`;

return [{
  json: {
    jobUrl,
    jobDescription,
    company,
    jobTitle,
    location,
    jobRequirements,
    userSkills,
    companySql,
    jobTitleSql,
    locationSql,
    jobDescSql,
    companyShell,
    jobTitleShell,
    vaultPath,
    folderName,
    year: String(year),
    month,
    day,
    timestamp: now.toISOString()
  }
}];

